import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.ZhLefgN8.js";const f=JSON.parse('{"title":"FOK 与 IOC 订单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/order-types/fok-and-ioc.md","filePath":"zh-CN/stock-trading/order-types/fok-and-ioc.md"}'),d={name:"stock-trading/order-types/fok-and-ioc.md"};function i(n,t,c,l,s,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="fok-与-ioc-订单" tabindex="-1">FOK 与 IOC 订单 <a class="header-anchor" href="#fok-与-ioc-订单" aria-label="Permalink to &quot;FOK 与 IOC 订单&quot;">​</a></h1><p>以下两种订单类型适用于长桥新加坡柜台。</p><h2 id="全部成交或立即取消单-fok" tabindex="-1">全部成交或立即取消单（FOK） <a class="header-anchor" href="#全部成交或立即取消单-fok" aria-label="Permalink to &quot;全部成交或立即取消单（FOK）&quot;">​</a></h2><p>FOK（Fill or Kill）是一种有条件生效的订单，订单必须立即全部执行或完全不执行。若订单不能全部成交，则会被立即取消。</p><p>适用场景：需要确保一次性全部买入/卖出指定数量，不接受部分成交。</p><h2 id="立即成交并取消剩余单-ioc" tabindex="-1">立即成交并取消剩余单（IOC） <a class="header-anchor" href="#立即成交并取消剩余单-ioc" aria-label="Permalink to &quot;立即成交并取消剩余单（IOC）&quot;">​</a></h2><p>IOC（Immediate or Cancel）是一种买入或卖出证券的订单，下单后会尝试立即执行全部或部分订单，未成交的剩余部分会被立即取消。</p><p>适用场景：希望尽快成交，可以接受部分成交，剩余部分不再保留。</p><h2 id="fok-与-ioc-的区别" tabindex="-1">FOK 与 IOC 的区别 <a class="header-anchor" href="#fok-与-ioc-的区别" aria-label="Permalink to &quot;FOK 与 IOC 的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>FOK</th><th>IOC</th></tr></thead><tbody><tr><td>部分成交</td><td>不允许，必须全部成交</td><td>允许部分成交</td></tr><tr><td>未成交处理</td><td>整单取消</td><td>仅取消未成交部分</td></tr></tbody></table>',10)])])}const _=a(d,[["render",i]]);export{f as __pageData,_ as default};
